import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

function MyVideosPage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deletingId, setDeletingId] = useState(null);
  const [currentUser, setCurrentUser] = useState(null);
  const navigate = useNavigate();

  const getCurrentUser = () => {
    let username = localStorage.getItem('username');
    if (username) return username;
    
    const token = localStorage.getItem('access');
    if (token) {
      try {
        const payload = JSON.parse(atob(token.split('.')[1]));
        username = payload.username;
        if (username) localStorage.setItem('username', username);
        return username;
      } catch (e) {
        return null;
      }
    }
    return null;
  };

  useEffect(() => {
    const token = localStorage.getItem('access');
    if (!token) {
      navigate('/login');
      return;
    }
    
    const user = getCurrentUser();
    setCurrentUser(user);
    fetchVideos(user);
  }, [navigate]);

  const fetchVideos = async (user) => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://localhost:8000/api/videos/', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      const userVideos = response.data.filter(video => video.uploaded_by_name === user);
      setVideos(userVideos);
      setLoading(false);
    } catch (error) {
      console.error('Ошибка загрузки:', error);
      setLoading(false);
    }
  };

  const handleDelete = async (videoId) => {
    if (!window.confirm('Вы уверены, что хотите удалить это видео?')) return;
    
    setDeletingId(videoId);
    try {
      const token = localStorage.getItem('access');
      await axios.delete(`http://localhost:8000/api/videos/${videoId}/`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      setVideos(videos.filter(v => v.id !== videoId));
      alert('✅ Видео удалено');
    } catch (error) {
      alert('❌ Не удалось удалить видео');
    } finally {
      setDeletingId(null);
    }
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
        <div className="card" style={{ padding: 48, textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>📼</div>
          <p>Загрузка...</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 1000, margin: '0 auto' }}>
      <div style={{ marginBottom: 32 }}>
        <h1 style={{ fontSize: 28, fontWeight: 700, marginBottom: 8 }}>📼 Мои видео</h1>
        <p style={{ color: 'var(--text-secondary)' }}>
          Вы вошли как <span style={{ color: 'var(--accent)', fontWeight: 500 }}>{currentUser}</span>
        </p>
      </div>
      
      {videos.length === 0 ? (
        <div className="card" style={{ textAlign: 'center', padding: 64 }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>📭</div>
          <p style={{ fontSize: 18, marginBottom: 24 }}>У вас пока нет загруженных видео</p>
          <Link to="/upload" className="btn btn-primary">
            + Загрузить видео
          </Link>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {videos.map(video => (
            <div key={video.id} className="card" style={{ padding: 20, display: 'flex', gap: 20, alignItems: 'center', flexWrap: 'wrap' }}>
              {/* Превью */}
              <div style={{ width: 160, flexShrink: 0 }}>
                {video.thumbnail ? (
                  <img 
                    src={`http://localhost:8000${video.thumbnail}`}
                    alt={video.title}
                    style={{ width: '100%', aspectRatio: '16/9', objectFit: 'cover', borderRadius: 'var(--radius-md)' }}
                  />
                ) : video.video_file ? (
                  <video 
                    src={`http://localhost:8000${video.video_file}`}
                    style={{ width: '100%', aspectRatio: '16/9', objectFit: 'cover', borderRadius: 'var(--radius-md)' }}
                    muted
                  />
                ) : (
                  <div style={{
                    width: '100%',
                    aspectRatio: '16/9',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: 32,
                    backgroundColor: '#f0f0f0',
                    borderRadius: 'var(--radius-md)'
                  }}>
                    🎬
                  </div>
                )}
              </div>
              
              {/* Информация */}
              <div style={{ flex: 1 }}>
                <Link to={`/video/${video.id}`} style={{ textDecoration: 'none' }}>
                  <h3 style={{ color: 'var(--text-primary)', marginBottom: 8 }}>{video.title}</h3>
                </Link>
                <p style={{ color: 'var(--text-secondary)', fontSize: 13, marginBottom: 8 }}>
                  👁️ {video.views || 0} просмотров • 📅 {new Date(video.created_at).toLocaleDateString()}
                </p>
                {video.description && (
                  <p style={{ color: 'var(--text-secondary)', fontSize: 14 }}>
                    {video.description.length > 100 ? video.description.slice(0, 100) + '...' : video.description}
                  </p>
                )}
              </div>
              
              {/* Кнопка удаления */}
              <button
                onClick={() => handleDelete(video.id)}
                disabled={deletingId === video.id}
                className="btn btn-danger"
                style={{ padding: '8px 20px' }}
              >
                {deletingId === video.id ? 'Удаление...' : '🗑️ Удалить'}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default MyVideosPage;
